  pollingTimer: NodeJS.Timeout | null;
  loading: boolean;
  // 手机号登录
  phone: string;
  code: string;
  countdown: number;
}
```

**响应式适配：**
- >1200px：卡片宽度400px，水平居中
- 768-1200px：卡片宽度80%
- <768px：卡片宽度95%，全宽

